"use client";

import styles from "./auditorsTable.module.css";
import Image from "next/image";

type Auditor = {
  id: string;
  name: string;
  phone: string;
  department: string;
  lastActivity: string;
  status: "Active" | "Offline" | "Wait";
};

export default function AuditorsTable({ data }: { data: Auditor[] }) {
  return (
    <div className={styles.wrapper}>
      {/* header */}
      <div className={styles.header}>
        <button className={styles.addBtn}>
          إضافة مجرد جديد
          <span className={styles.plus}>+</span>
        </button>

        <div className={styles.searchBox}>
          <input placeholder="بحث..." />
        </div>
      </div>

      {/* table */}
      <table className={styles.table}>
        <thead>
          <tr>
            <th>الاسم</th>
            <th>رقم الهاتف</th>
            <th>القسم</th>
            <th>آخر نشاط</th>
            <th>الحالة</th>
            <th>الإجراءات</th>
          </tr>
        </thead>

        <tbody>
          {data.map((emp) => (
            <tr key={emp.id}>
              <td>{emp.name}</td>
              <td>{emp.phone}</td>
              <td>{emp.department}</td>
              <td>{emp.lastActivity}</td>

              <td>
                <span className={`${styles.status} ${styles[emp.status]}`}>
                  {emp.status}
                </span>
              </td>

              <td className={styles.actions}>
                <div className={styles.toggle}></div>

                <Image
                  src="/icon/delete.svg"
                  alt="delete"
                  width={18}
                  height={18}
                />

                <Image src="/icon/edit.svg" alt="edit" width={18} height={18} />

                <Image
                  src="/icon/mobile.svg"
                  alt="phone"
                  width={18}
                  height={18}
                />
              </td>
            </tr>
          ))}
        </tbody>
      </table>

      {/* pagination */}
      <div className={styles.pagination}>
        <span>01</span>
        <span>02</span>
        <span>03</span>
        <span>...</span>
        <span>04</span>
        <span>05</span>
        <span>06</span>
      </div>
    </div>
  );
}
